cd /workspace/YatCC && cat > /tmp/debug_tokens.cpp << 'EOF'
#include <iostream>
#include "SYsULexer.h"
#include <fstream>

int main() {
    std::ifstream inFile("build/test/task0/functional-0/000_main.sysu.c");
    antlr4::ANTLRInputStream input(inFile);
    SYsULexer lexer(&input);
    antlr4::CommonTokenStream tokens(&lexer);
    tokens.fill();

    for (auto* token : tokens.getTokens()) {
        std::cout << "Token: " << token->getText() 
                  << " Line: " << token->getLine() 
                  << " Col: " << token->getCharPositionInLine() 
                  << std::endl;
    }
    return 0;
}
EOF
